22	/**
23	 * Unpacks and validates route parameters for the game detail page.
24	 *
25	 * Validates the `id` parameter as a positive integer, retrieves the
26	 * corresponding game day, and handles redirects to the canonical URL if needed.
27	 *
28	 * @param params - The route parameters object containing the `id` property
29	 * @returns A promise that resolves to an object containing the validated
30	 * `gameDay`
31	 * @throws Calls `notFound()` if the game day cannot be found or the ID is
32	 * invalid
33	 * @throws Calls `permanentRedirect()` if the current URL doesn't match the
34	 * canonical URL
35	 */
36	const unpackParams = cache(async (
37	    params: PageProps['params'],
38	) => {
39	    const { id } = await params;
40	
41	    const gameDayId = z.coerce.number().int().min(1).safeParse(id);
42	    const gameDay = gameDayId.success ? await gameDayService.get(gameDayId.data) : undefined;
43	    if (!gameDay) notFound();
44	
45	    const canonicalUrl = `/footy/game/${gameDay.id}`;
46	    const currentUrl = `/footy/game/${id}`;
47	    if (currentUrl !== canonicalUrl) permanentRedirect(canonicalUrl);
48	
49	    return { gameDay };
50	});
51	
52	/**
53	 * Generates metadata for a game page.
54	 * @param props - The page props containing route parameters
55	 * @param props.params - Route parameters including the game ID
56	 * @returns A promise that resolves to metadata with the game title and date
57	 */
58	export async function generateMetadata(props: PageProps): Promise<Metadata> {
59	    const { gameDay } = await unpackParams(props.params);
60	
61	    return {
62	        title: formatDate(gameDay.date),
63	    };
64	}
