66	/**
67	 * Displays a football game day page with game details, team information, and
68	 * navigation.
69	 *
70	 * This is an async Server Component that fetches game data, determines user
71	 * role, and renders game results, player teams, and administrative controls
72	 * based on permissions.
73	 *
74	 * @component
75	 * @param {PageProps} props - The page component props
76	 * @param {object} props.params - Route parameters containing the game ID
77	 * @returns {Promise<React.ReactElement>} A flex container with game navigation,
78	 * admin controls, and game summary
79	 *
80	 * @remarks
81	 * - Fetches previous and next game days for navigation
82	 * - Retrieves team rosters (up to 10 players per team) for the current game day
83	 * - Calculates game winners from team data
84	 * - Only displays the GameResultForm if the user has an 'admin' role
85	 * - Navigation links (Previous/Next) are conditionally rendered based on data
86	 *   availability
87	 *
88	 * @requires getUserRole - To determine user permissions
89	 * @requires unpackParams - To extract gameDay from route params
90	 * @requires gameDayService.getPrevious - To fetch previous game
91	 * @requires gameDayService.getNext - To fetch next game
92	 * @requires outcomeService.getTeamPlayersByGameDay - To fetch team rosters
93	 * @requires getGameWinnersFromTeams - To calculate match winners
94	 */
95	const GamePage = async (props: PageProps) => {
96	    const { gameDay } = await unpackParams(props.params);
97	    const [role, prevGameDay, nextGameDay, teamA, teamB] = await Promise.all([
98	        getUserRole(),
99	        gameDayService.getPrevious(gameDay.id),
100	        gameDayService.getNext(gameDay.id),
101	        outcomeService.getTeamPlayersByGameDay(gameDay.id, 'A', 10),
102	        outcomeService.getTeamPlayersByGameDay(gameDay.id, 'B', 10),
103	    ]);
104	    const winners = getGameWinnersFromTeams(teamA, teamB);
105	
106	    return (
107	        <Flex w="100%" direction="column" gap="md">
108	            <AutoRefresh channels={[FootyChannel.Games, FootyChannel.Results]} />
109	            <GameDaySummary
110	                gameDay={gameDay}
111	                prevGameDay={prevGameDay}
112	                nextGameDay={nextGameDay}
113	                teamA={teamA}
114	                teamB={teamB}
115	            />
116	            {role === 'admin' && !!gameDay.game && (
117	                <GameResultForm
118	                    gameDayId={gameDay.id}
119	                    bibs={gameDay.bibs ?? null}
120	                    winners={winners}
121	                    setGameResult={setGameResult}
122	                />
123	            )}
124	        </Flex>
125	    );
126	};
